const body = $input.first().json.body;
if (!body.footage_url) throw new Error('ບໍ່ມີ footage_url');
if (!body.description_lao) throw new Error('ຕ້ອງມີຄຳອະທິບາຍ');
return [{ json: {
  footage_url: body.footage_url,
  description_lao: body.description_lao,
  style: body.style || 'promo',
  has_voiceover: body.has_voiceover || false,
  platforms: body.platforms || ['tiktok','facebook'],
  schedule_time: body.schedule_time || null,
  job_id: body.job_id || 'vid_' + Date.now(),
  brand_name: process.env.BRAND_NAME || 'PHANUKNGAN',
  contact: process.env.CONTACT_PHONE || '020-XXXX-XXXX'
}}];

