const captionResp = $input.first().json;
const caption = captionResp.content[0].text.trim();
const shotResp = $('ເຜົາ Subtitle ໃສ່ຄລິບ').first().json;
const jobData = $('ກວດຂໍ້ມູນ').first().json;
return [{ json: { job_id: jobData.job_id, video_url: shotResp.response?.url || shotResp.id || 'pending', caption, platforms: jobData.platforms, schedule_time: jobData.schedule_time, status: 'awaiting_approval' } }];
